/** Checks a theorem-backed root identity over every parseable W3C and RDF4J corpus query. */
@Tag("slow")
class CorpusCertificateAgreementTest {
	private static final String ENCODING_UNSUPPORTED_REASON = "The algebra trees cannot be encoded for independent certificate replay";
	private static final List<Corpus> CORPORA = List.of(
			new Corpus("w3c-sparql-1.0", "testcases-sparql-1.0-w3c", SemanticsTarget.SPARQL_1_1),
			new Corpus("w3c-sparql-1.1", "testcases-sparql-1.1-w3c", SemanticsTarget.SPARQL_1_1),
			new Corpus("rdf4j-sparql-1.1", "testcases-sparql-1.1", SemanticsTarget.SPARQL_1_1),
			new Corpus("w3c-sparql-1.2", "testcases-sparql-1.2-w3c", SemanticsTarget.SPARQL_1_2_DRAFT),
			new Corpus("rdf4j-sparql-1.2", "testcases-sparql-1.2", SemanticsTarget.SPARQL_1_2_DRAFT));

	@Test
	void javaAndFormalCertificatesAgreeAcrossQueryCorpora() throws IOException {
		Path corpusRoot = Path.of(System.getProperty(
				"equivalence.certification.corpusRoot",
				"../../../testsuites/sparql/src/main/resources"))
				.toAbsolutePath()
				.normalize();
		Path outputDirectory = Path.of(System.getProperty(
				"equivalence.certification.corpusOutputDir",
				"target/certification/corpus"));
		long timeBudgetSeconds = Long.getLong("equivalence.certification.corpusTimeBudgetSeconds", 1_800L);
		Instant deadline = Instant.now().plusSeconds(timeBudgetSeconds);
		assertTrue(Files.isDirectory(corpusRoot), () -> "missing SPARQL corpus root: " + corpusRoot);
		Files.createDirectories(outputDirectory);

		try (BufferedWriter certificates = writer(outputDirectory.resolve("certificates.jsonl"));
				BufferedWriter summary = writer(outputDirectory.resolve("summary.csv"));
				BufferedWriter unsupportedParse = writer(outputDirectory.resolve("unsupported-parse.csv"));
				BufferedWriter unsupportedAlgebra = writer(outputDirectory.resolve("unsupported-algebra.csv"));
				BufferedWriter unsupportedCertificate = writer(
						outputDirectory.resolve("unsupported-certificate.csv"))) {
			summary.write(
					"corpus,semanticsTarget,versionIri,queryFiles,parsed,unsupportedParse,unsupportedAlgebra,unsupportedCertificate,certificates\n");
			unsupportedParse.write("corpus,semanticsTarget,query,exception,message\n");
			unsupportedAlgebra.write("corpus,semanticsTarget,query,reason\n");
			unsupportedCertificate.write("corpus,semanticsTarget,query,reason\n");
			int totalFiles = 0;
			int totalParsed = 0;
			int totalUnsupported = 0;
			int totalUnsupportedAlgebra = 0;
			int totalUnsupportedCertificate = 0;
			int totalCertificates = 0;
			for (Corpus corpus : CORPORA) {
				CorpusResult result = checkCorpus(corpusRoot, corpus, deadline, certificates, unsupportedParse,
						unsupportedAlgebra, unsupportedCertificate);
				totalFiles += result.queryFiles();
				totalParsed += result.parsed();
				totalUnsupported += result.unsupportedParse();
				totalUnsupportedAlgebra += result.unsupportedAlgebra();
				totalUnsupportedCertificate += result.unsupportedCertificate();
				totalCertificates += result.certificates();
				summary.write(csv(corpus.name()) + "," + corpus.target() + ","
						+ csv(corpus.target().getVersionIri().orElseThrow()) + "," + result.queryFiles() + ","
						+ result.parsed() + "," + result.unsupportedParse() + "," + result.unsupportedAlgebra() + ","
						+ result.unsupportedCertificate() + "," + result.certificates() + "\n");
			}
			assertTrue(totalFiles > 0, "corpus inventory contained no .rq files");
			assertEquals(totalFiles, totalParsed + totalUnsupported, "every corpus query must be classified");
			assertEquals(totalParsed, totalCertificates + totalUnsupportedAlgebra + totalUnsupportedCertificate,
					"every parsed corpus query must be certified or explicitly unsupported");
			summary.write("TOTAL,,," + totalFiles + "," + totalParsed + "," + totalUnsupported + ","
					+ totalUnsupportedAlgebra + "," + totalUnsupportedCertificate + "," + totalCertificates + "\n");
		}
	}

	private static CorpusResult checkCorpus(
			Path corpusRoot,
			Corpus corpus,
			Instant deadline,
			BufferedWriter certificates,
			BufferedWriter unsupportedParseWriter,
			BufferedWriter unsupportedAlgebraWriter,
			BufferedWriter unsupportedCertificateWriter) throws IOException {
		Path directory = corpusRoot.resolve(corpus.directory()).normalize();
		assertTrue(directory.startsWith(corpusRoot) && Files.isDirectory(directory),
				() -> "missing or escaped corpus directory: " + directory);
		List<Path> queries = new ArrayList<>();
		try (var paths = Files.walk(directory)) {
			paths.filter(Files::isRegularFile)
					.filter(path -> path.getFileName().toString().endsWith(".rq"))
					.sorted(Comparator.comparing(Path::toString))
					.forEach(queries::add);
		}
		assertFalse(queries.isEmpty(), () -> "corpus contains no .rq files: " + directory);

		int parsed = 0;
		int unsupportedParse = 0;
		int unsupportedAlgebra = 0;
		int unsupportedCertificate = 0;
		int certificateCount = 0;
		CheckOptions options = CheckOptions.builder()
				.semanticsTarget(corpus.target())
				.observationMode(ObservationMode.BAG)
				.contextMode(ContextMode.ALL_BINDINGS)
				.boundedCounterexampleSearch(false)
				.build();
		for (Path query : queries) {
			assertTrue(Instant.now().isBefore(deadline), "time budget truncated corpus certification");
			String source = Files.readString(query, StandardCharsets.UTF_8);
			String baseIri = query.toUri().toString();
			TupleExpr parsedQuery;
			try {
				parsedQuery = new SPARQLParser().parseQuery(source, baseIri).getTupleExpr();
			} catch (RuntimeException first) {
				assertDeterministicParseFailure(source, baseIri, first);
				unsupportedParseWriter.write(csv(corpus.name()) + "," + corpus.target() + ","
						+ csv(corpusRoot.relativize(query).toString()) + "," + csv(first.getClass().getName()) + ","
						+ csv(String.valueOf(first.getMessage())) + "\n");
				unsupportedParse++;
				continue;
			}
			parsed++;
			TupleExpr queryBody = parsedQuery instanceof QueryRoot root ? root.getArg().clone() : parsedQuery;
			Extension opaqueQuery = new Extension(
					queryBody,
					new ExtensionElem(new BNodeGenerator(), "__equivalence_certificate_scope"));
			TupleExpr original = new Union(new EmptySet(), opaqueQuery.clone());
			TupleExpr candidate = opaqueQuery;
			SemanticsValidator.Validation validation = new SemanticsValidator().validate(original, corpus.target());
			EquivalenceResult result = new AlgebraEquivalenceChecker(options).check(original, candidate);
			if (!validation.isSupported()) {
				assertEquals(EquivalenceStatus.UNKNOWN, result.getStatus(),
						"unsupported corpus algebra must fail closed");
				assertEquals(validation.getReason(), result.getReason());
				unsupportedAlgebraWriter.write(csv(corpus.name()) + "," + corpus.target() + ","
						+ csv(corpusRoot.relativize(query).toString()) + "," + csv(validation.getReason()) + "\n");
				unsupportedAlgebra++;
				continue;
			}
			if (result.getStatus() == EquivalenceStatus.UNKNOWN
					&& ENCODING_UNSUPPORTED_REASON.equals(result.getReason())) {
				unsupportedCertificateWriter.write(csv(corpus.name()) + "," + corpus.target() + ","
						+ csv(corpusRoot.relativize(query).toString()) + "," + csv(result.getReason()) + "\n");
				unsupportedCertificate++;
				continue;
			}
			assertEquals(EquivalenceStatus.EQUIVALENT, result.getStatus(),
					() -> corpus.name() + ": " + query + ": " + result.getReason());
			NormalizationProof proof = assertInstanceOf(
					NormalizationProof.class, result.getEvidence().orElseThrow());
			NormalizationCertificate certificate = proof.getCertificate().orElseThrow();
			assertEquals(corpus.target(), certificate.getSemanticsTarget());
			assertEquals(1, certificate.getOriginalSteps().size(), "corpus proof must be root-local");
			CertificateStep step = certificate.getOriginalSteps().get(0);
			assertEquals(RuleId.UNION_EMPTY_IDENTITY, step.getRule());
			assertEquals("$", step.getNodePath());
			assertTrue(certificate.getCandidateSteps().isEmpty(), "opaque candidate must need no rewrite");
			assertTrue(new ProofKernel(options).verify(original, candidate, proof));
			certificates.write(certificate.toJson());
			certificates.newLine();
			certificateCount++;
		}
		return new CorpusResult(
				queries.size(), parsed, unsupportedParse, unsupportedAlgebra, unsupportedCertificate, certificateCount);
	}

	private static void assertDeterministicParseFailure(String source, String baseIri, RuntimeException first) {
		try {
			new SPARQLParser().parseQuery(source, baseIri);
			fail("query parse failure was not reproducible");
		} catch (RuntimeException second) {
			assertEquals(first.getClass(), second.getClass(), "parse failure class changed between replays");
			assertEquals(first.getMessage(), second.getMessage(), "parse failure message changed between replays");
		}
	}

	private static BufferedWriter writer(Path path) throws IOException {
		return Files.newBufferedWriter(
				path,
				StandardCharsets.UTF_8,
				StandardOpenOption.CREATE,
				StandardOpenOption.TRUNCATE_EXISTING);
	}

	private static String csv(String value) {
		return '"' + value.replace("\"", "\"\"").replace("\r", "\\r").replace("\n", "\\n") + '"';
	}

	private record Corpus(String name, String directory, SemanticsTarget target) {
	}

	private record CorpusResult(
			int queryFiles,
			int parsed,
			int unsupportedParse,
			int unsupportedAlgebra,
			int unsupportedCertificate,
			int certificates) {
	}
}
